import http from 'k6/http';
import { check } from 'k6';

export const options = {
  scenarios: {
    warmup: { executor: 'constant-vus', vus: 5, duration: '10s',
              tags: { phase: 'warmup' } },
    test: { executor: 'constant-vus', vus: 50, duration: '30s',
            startTime: '10s', tags: { phase: 'test' } },
  },
  thresholds: {
    'http_req_duration{phase:test}': ['p(99)<200'],
    'http_req_failed{phase:test}': ['rate<0.001'],
  },
};

export default function() {
  check(http.get('http://api/orders'), { 'is 200': r => r.status === 200 });
}
